sql:
SELECT AVG(magnitude) 
FROM loads 
WHERE simulation_id = 1;

SELECT DISTINCT u.user_name
FROM users u
INNER JOIN simulations s ON u.user_id = s.created_by
WHERE s.simulation_id NOT IN (
    SELECT l.simulation_id FROM loads l
)
AND s.simulation_id NOT IN (
    SELECT bc.simulation_id FROM boundary_conditions bc
);

SELECT magnitude, location, unit
FROM loads
WHERE simulation_id = 2;

SELECT s.simulation_id, s.scenario_id, s.model_id, s.status
FROM simulations s
WHERE s.run_date > '2022-01-01' AND s.status = 'completed';

SELECT m.model_id, m.model_name, m.material_id
FROM models AS m
INNER JOIN materials AS mat ON m.material_id = mat.material_id;

SELECT scenarios.scenario_name, users.user_name
FROM scenarios
JOIN users ON scenarios.created_by = users.user_id;

SELECT DISTINCT s.simulation_id
FROM simulations s
JOIN loads l ON s.simulation_id = l.simulation_id;
